{
  "name": "send-communication-function",
  "version": "1.0.0",
  "description": "A Node.js Cloud Function to send emails via SendGrid and SMS via Twilio.",
  "main": "index.js",
  "scripts": {
    "start": "node index.js"
  },
  "dependencies": {
    "@sendgrid/mail": "^7.7.0",
    "twilio": "^4.20.0"
  },
  "engines": {
    "node": ">=16.0.0"
  }
}

// index.js
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

// --- SendGrid Initialization ---
const SENDGRID_API_KEY = process.env.SENDGRID_API_KEY;
const SENDGRID_SENDER_EMAIL = process.env.SENDGRID_SENDER_EMAIL;

if (SENDGRID_API_KEY) {
  sgMail.setApiKey(SENDGRID_API_KEY);
} else {
  console.warn('SENDGRID_API_KEY environment variable is not set. Email functionality may be unavailable.');
}

// --- Twilio Initialization ---
const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID;
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN;
const TWILIO_PHONE_NUMBER = process.env.TWILIO_PHONE_NUMBER; // Your Twilio sender phone number (E.164 format)

let twilioClient;
if (TWILIO_ACCOUNT_SID && TWILIO_AUTH_TOKEN) {
  twilioClient = new twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);
} else {
  console.warn('TWILIO_ACCOUNT_SID or TWILIO_AUTH_TOKEN environment variables are not set. SMS functionality may be unavailable.');
}
if (!TWILIO_PHONE_NUMBER) {
  console.warn('TWILIO_PHONE_NUMBER environment variable is not set. SMS sending may fail.');
}

/**
 * Handles HTTP requests to send emails via SendGrid or SMS via Twilio.
 *
 * This function expects a JSON payload in the request body with a 'type' field:
 *
 * For Email:
 * {
 *   "type": "email",
 *   "to": "recipient@example.com",
 *   "subject": "Your Email Subject",
 *   "text": "Plain text content of the email.",
 *   "html": "<strong>HTML content</strong> of the email."
 * }
 *
 * For SMS:
 * {
 *   "type": "sms",
 *   "to": "+1234567890", // Recipient phone number in E.164 format (e.g., +15551234567)
 *   "body": "Your SMS message content."
 * }
 *
 * Environment variables required:
 * - SENDGRID_API_KEY: Your SendGrid API Key.
 * - SENDGRID_SENDER_EMAIL: The sender email address for SendGrid.
 * - TWILIO_ACCOUNT_SID: Your Twilio Account SID.
 * - TWILIO_AUTH_TOKEN: Your Twilio Auth Token.
 * - TWILIO_PHONE_NUMBER: Your Twilio phone number for sending SMS (in E.164 format).
 *
 * @param {object} req The HTTP request object.
 * @param {object} res The HTTP response object.
 */
exports.sendCommunication = async (req, res) => {
  if (req.method !== 'POST') {
    return res.status(405).send('Method Not Allowed. This function only accepts POST requests.');
  }

  const { type, to, subject, text, html, body } = req.body;

  if (!type || !to) {
    return res.status(400).send('Missing "type" or "to" in request body.');
  }

  try {
    if (type === 'email') {
      if (!SENDGRID_API_KEY || !SENDGRID_SENDER_EMAIL) {
        throw new Error('SendGrid API key or sender email is not configured. Cannot send email.');
      }
      if (!subject || (!text && !html)) {
        return res.status(400).send('Missing "subject" or email content ("text" or "html") for email.');
      }

      const msg = {
        to: to,
        from: SENDGRID_SENDER_EMAIL,
        subject: subject,
        text: text,
        html: html,
      };

      await sgMail.send(msg);
      console.log(`Email sent successfully to: ${to}`);
      res.status(200).json({ status: 'success', message: `Email sent to ${to}` });

    } else if (type === 'sms') {
      if (!twilioClient || !TWILIO_PHONE_NUMBER) {
        throw new Error('Twilio client or sender phone number is not configured. Cannot send SMS.');
      }
      if (!body) {
        return res.status(400).send('Missing "body" for SMS message.');
      }

      const message = await twilioClient.messages.create({
        body: body,
        to: to,
        from: TWILIO_PHONE_NUMBER,
      });

      console.log(`SMS sent successfully to: ${to}, SID: ${message.sid}`);
      res.status(200).json({ status: 'success', message: `SMS sent to ${to}`, sid: message.sid });

    } else {
      res.status(400).send('Invalid communication type. Must be "email" or "sms".');
    }
  } catch (error) {
    console.error(`Error sending communication (${type}):`, error);
    if (error.response && error.response.body && error.response.body.errors) {
        // Log detailed SendGrid errors
        console.error('SendGrid API Errors:', error.response.body.errors);
    }
    res.status(500).send(`Failed to send ${type}: ${error.message}`);
  }
};